import sys

# Increase recursion limit for deep DFS
sys.setrecursionlimit(2 * 10**5 + 50) 

def solve():
    N, M = map(int, sys.stdin.readline().split())

    if N == 0:
        print(0)
        return

    adj = [[] for _ in range(N)]
    for _ in range(M):
        u, v = map(int, sys.stdin.readline().split())
        adj[u].append(v)

    dfs_num = [-1] * N
    dfs_low = [-1] * N
    on_stack = [False] * N
    scc_stack = []
    scc_id = [-1] * N

    timer = 0
    scc_idx = 0

    scc_adj = [set() for _ in range(N)]
    in_degree_scc = [0] * N

    def tarjan_dfs(u):
        nonlocal timer, scc_idx
        dfs_num[u] = dfs_low[u] = timer
        timer += 1
        scc_stack.append(u)
        on_stack[u] = True

        for v in adj[u]:
            if dfs_num[v] == -1:
                tarjan_dfs(v)
                dfs_low[u] = min(dfs_low[u], dfs_low[v])
            elif on_stack[v]:
                dfs_low[u] = min(dfs_low[u], dfs_num[v])

        if dfs_low[u] == dfs_num[u]:
            while True:
                w = scc_stack.pop()
                on_stack[w] = False
                scc_id[w] = scc_idx
                if w == u:
                    break
            scc_idx += 1

    for i in range(N):
        if dfs_num[i] == -1:
            tarjan_dfs(i)

    for u in range(N):
        for v in adj[u]:
            s_u = scc_id[u]
            s_v = scc_id[v]
            if s_u != s_v:
                if s_v not in scc_adj[s_u]:
                    scc_adj[s_u].add(s_v)
                    in_degree_scc[s_v] += 1

    source_sccs = 0
    for i in range(scc_idx):
        if in_degree_scc[i] == 0:
            source_sccs += 1

    print(source_sccs)

solve()
